import Vue from 'vue'
import VueRouter from 'vue-router'
import MainPage from '../views/MainPage.vue'
import Idioms from '../views/Idioms.vue'
import Words from '../views/Words.vue'
import Auth from '../components/Auth.vue'

Vue.use(VueRouter)

const routes = [
  {
    path: '/',
    name: 'Auth',
    component: Auth
  },
  {
    path: '/idioms',
    name: 'Idioms',
    component: Idioms,
    props: true
  },
  {
    path: '/words_folders',
    name: 'Words',
    component: Words,
    props: true
  },
  {
    path: '/main_page',
    name: 'MainPage',
    component: MainPage,
    props: true
  },
]

const router = new VueRouter({
  mode: 'history',
  base: process.env.BASE_URL,
  routes
})

export default router
