import { getDatabase, ref, set, push } from "firebase/database";
import { fb } from "@/firebase-config"

export default {
    state: {
        
    },

    actions: {
        async addNewItem(ctx, data) {
            try {
                let path
                if(data.type === 'Idiom') {
                    path = 'idioms/'
                } else if(data.type === 'Word') {
                    path = 'words/'
                }
                console.log(path)
                const postListRef = ref(fb.database, path + data.userId);
                const newIdiom = push(postListRef);
                set(newIdiom, {
                    idiom: data.new_value,
                    meaning: data.new_meaning,
                });
              } catch (e) {
                console.error("Error adding document: ", e);
              }
        },

        async addNewWord(ctx, data) {
          try {
              let path
              if(data.type === 'Idiom') {
                  path = 'idioms/'
              } else if(data.type === 'Word') {
                  path = 'words/'
              }
              console.log(path)
              const postListRef = ref(fb.database, path + data.userId);
              const newIdiom = push(postListRef);
              set(newIdiom, {
                  idiom: data.new_value,
                  meaning: data.new_meaning,
              });
            } catch (e) {
              console.error("Error adding document: ", e);
            }
        },

        async addNewFolder(ctx, data) {
          try {
              let uid = `${data.userId}/`
              let folderName = `${data.newFolderName}/`
              const postListRef = ref(fb.database, 'words/' + uid + folderName );
              const newFolder = push(postListRef);
              set(newFolder, {word: data.word, meaning: data.meaning});
            } catch (e) {
              console.error("Error adding document: ", e);
            }
        },

        addColl() {
            const db = getDatabase();
            set(ref(db, 'words/' + 'userId' + 'Hous'), {
  
            });
          }
    }
}